VALUES ('9c144a2f-44cf-406e-9f52-91a1a746af1e', 'text', '1.4 Functions — Bikin Kode yang Bisa Dipake Ulang', '# 1.4 Functions — Bikin Kode yang Bisa Dipake Ulang

Function = blok kode dengan nama, bisa dipanggil kapan aja. Prinsip **DRY (Don''t Repeat Yourself)**.

## Deklarasi Function

```javascript
// Cara 1: Function Declaration
function sapa(nama) {
  return `Halo, ${nama}!`;
}
console.log(sapa("Budi")); // "Halo, Budi!"

// Cara 2: Function Expression (disimpen di variable)
const sapaV2 = function(nama) {
  return `Halo, ${nama}!`;
};

// Cara 3: Arrow Function (MODERN — favorit!)
const sapaV3 = (nama) => {
  return `Halo, ${nama}!`;
};

// Cara 4: Arrow Function (satu baris, return implisit)
const sapaV4 = nama => `Halo, ${nama}!`;
```

## Function Declaration vs Arrow Function

| Aspek | Function Declaration | Arrow Function |
|-------|---------------------|----------------|
| Syntax | `function()` | `() =>` |
| `this` | Dynamic (nge-this dari caller) | Lexical (nge-this dari sekitar) |
| Hoisting | Diangkat ke atas | Tidak |
| `arguments` object | Ada | Tidak (pake rest parameter) |
| Bisa jadi constructor | Ya (`new`) | Tidak |

```javascript
// Hoisting — function declaration bisa dipanggil SEBELUM deklarasi
console.log(kuadrat(5)); // 25 — HOISTING works!
function kuadrat(n) {
  return n * n;
}

/// Arrow tidak di-hoist
// console.log(kali(5, 2)); // ReferenceError: Cannot access before initialization
const kali = (a, b) => a * b;
```

## Parameter & Arguments

```javascript
// Multiple parameter
function tambah(a, b) {
  return a + b;
}

// Default parameter — kalo ga dikasih argumen
function sapa(nama = "Teman") {
  return `Halo, ${nama}!`;
}
console.log(sapa());        // "Halo, Teman!"
console.log(sapa("Budi")); // "Halo, Budi!"

// Rest parameter — kumpulin sisa argumen
function jumlahin(judul, ...angka) {
  const total = angka.reduce((a, b) => a + b, 0);
  return `${judul}: ${total}`;
}
console.log(jumlahin("Total", 1, 2, 3, 4, 5)); // "Total: 15"

// Named parameter pake destructuring
function createUser({ nama, umur = 17, kelas = "XII RPL" }) {
  return { nama, umur, kelas, createdAt: new Date() };
}
const user = createUser({ nama: "Budi" });
console.log(user); // { nama: "Budi", umur: 17, kelas: "XII RPL", ... }
```

## Higher-Order Functions (HOF) — Function dalam Function

HOF = function yang **menerima function sebagai argumen** atau **me-return function**.

```javascript
// 1. Callback — function sebagai argumen
function prosesAngka(angka, callback) {
  return callback(angka);
}

const double = n => n * 2;
console.log(prosesAngka(5, double)); // 10

// Langsung (inline)
console.log(prosesAngka(5, n => n * 2)); // 10

// 2. Function Factory — me-return function
function buatKalkulator(operasi) {
  return (a, b) => {
    switch (operasi) {
      case "+": return a + b;
      case "-": return a - b;
      case "*": return a * b;
      case "/": return b !== 0 ? a / b : "Error: bagi 0";
      default: return "Operasi ga dikenal";
    }
  };
}

const tambah = buatKalkulator("+");
const kali = buatKalkulator("*");
console.log(tambah(10, 5)); // 15
console.log(kali(3, 4));    // 12

### Closure — function inget variable dari scope luar
function counter() {
  let count = 0; // Private variable!
  return {
    increment: () => ++count,
    decrement: () => --count,
    getValue: () => count
  };
}

const myCounter = counter();
console.log(myCounter.increment()); // 1
console.log(myCounter.increment()); // 2
console.log(myCounter.decrement()); // 1
console.log(myCounter.getValue());  // 1

// 4. IIFE — Immediately Invoked Function Expression
// Function yang langsung jalan begitu didefinisikan
(function() {
  const privateVar = "ini rahasia";
  console.log("IIFE jalan!");
})();
// privateVar ga bisa diakses dari luar

// IIFE dengan parameter
(function(nama) {
  console.log(`Halo, ${nama}`);
})("Budi");

// IIFE modern — pake block scope aja
{
  const privateVar = "sama aja pake block scope";
  console.log(privateVar);
}
```

## Memoization — Caching Hasil Function

Teknik nyimpen hasil function biar kalo dipanggil lagi dengan argumen sama, ga perlu ngitung ulang:

```javascript
// Fibonacci tanpa memo — super lambat!
function fibSlow(n) {
  if (n <= 1) return n;
  return fibSlow(n - 1) + fibSlow(n - 2);
}
// fibSlow(50) — bisa sampe 60 detik!

// Fibonacci dengan memoization
function fibMemo() {
  const cache = {};
  return function fib(n) {
    if (n <= 1) return n;
    if (cache[n] !== undefined) return cache[n];
    cache[n] = fib(n - 1) + fib(n - 2);
    return cache[n];
  };
}
const fib = fibMemo();
console.log(fib(50)); // 12586269025 — instant!

// Generic memoize function
function memoize(fn) {
  const cache = new Map();
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      console.log(`Cache hit: ${key}`);
      return cache.get(key);
    }
    const result = fn(...args);
    cache.set(key, result);
    return result;
  };
}

// Pake
const expensiveCalc = memoize(n => {
  console.log(`Ngitung... ${n}`);
  return n * n;
});
console.log(expensiveCalc(5)); // Ngitung... 5 → 25
console.log(expensiveCalc(5)); // Cache hit: [5] → 25 (langsung!)
```

## Partial Application & Currying — Fungsi Parsial

Currying = teknik ngubah function yang nerima banyak argumen jadi rantai function yang masing-masing nerima satu argumen.

```javascript
// Currying manual
function multiply(a) {
  return function(b) {
    return function(c) {
      return a * b * c;
    };
  };
}
console.log(multiply(2)(3)(4)); // 24

// Currying pake arrow function
const multiply2 = a => b => c => a * b * c;
console.log(multiply2(2)(3)(4)); // 24

// Partial Application — fix argumen tertentu
function sapa(greeting, name) {
  return `${greeting}, ${name}!`;
}

const sapaIndonesia = sapa.bind(null, "Halo");
console.log(sapaIndonesia("Budi")); // "Halo, Budi!"
console.log(sapaIndonesia("Ani")); // "Halo, Ani!"

const sapaEnglish = sapa.bind(null, "Hello");
console.log(sapaEnglish("John")); // "Hello, John!"

// Utility buat partial
function partial(fn, ...fixedArgs) {
  return function(...remainingArgs) {
    return fn(...fixedArgs, ...remainingArgs);
  };
}

const tambahSepuluh = partial((a, b) => a + b, 10);
console.log(tambahSepuluh(5)); // 15
console.log(tambahSepuluh(20)); // 30
```

## Pure Function vs Side Effects

```javascript
// Pure function — input sama → output sama, ga ngaruh ke luar
function tambahPure(a, b) {
  return a + b;
}

// Impure function — punya side effect
let total = 0;
function tambahImpure(n) {
  total += n; // Side effect: ngubah variable luar!
  return total;
}
```

**Kenapa pure function penting?** Predictable, gampang di-test, gampang di-debug.

## Method Chaining

Function yang me-return `this` (object-nya sendiri) sehingga bisa dirantai:

```javascript
const kalkulator = {
  nilai: 0,
  tambah(n) { this.nilai += n; return this; },
  kurang(n) { this.nilai -= n; return this; },
  kali(n) { this.nilai *= n; return this; },
  bagi(n) { if (n !== 0) this.nilai /= n; return this; },
  hasil() { console.log(`Hasil: ${this.nilai}`); return this; }
};

kalkulator
  .tambah(10)
  .kali(2)
  .kurang(5)
  .bagi(3)
  .hasil(); // Hasil: 5
```

## Error Handling in Functions

```javascript
function bagi(a, b) {
  // Guard clause — cek dulu, kalo error langsung return/throw
  if (typeof a !== "number" || typeof b !== "number") {
    throw new TypeError("Input harus number");
  }
  if (b === 0) {
    throw new Error("Pembagian dengan nol!");
  }
  return a / b;
}

// Try-catch
try {
  const result = bagi(10, 0);
  console.log(result);
} catch (error) {
  console.error(`Error: ${error.message}`);
} finally {
  console.log("Kode ini jalan terus");
}
```

