## 3. Controller

`src/controllers/todo.controller.ts`:

```typescript
import { Request, Response, NextFunction } from ''express'';
import { todoRepository } from ''../database/todo.repository'';
import { validateCreateTodo, validateUpdateTodo } from ''../validators/todo.validator'';

export const todoController = {
  // GET /api/todos
  async getAll(req: Request, res: Response, next: NextFunction) {
    try {
      const todos = await todoRepository.findAll();
      res.json({
        success: true,
        message: ''Data todos berhasil diambil'',
        data: todos,
      });
    } catch (err) {
      next(err); // lempar ke error handler middleware
    }
  },

  // GET /api/todos/:id
  async getById(req: Request, res: Response, next: NextFunction) {
    try {
      const id = parseInt(req.params.id);

      if (isNaN(id)) {
        return res.status(400).json({
          success: false,
          message: ''ID harus berupa angka'',
        });
      }

      const todo = await todoRepository.findById(id);
      if (!todo) {
        return res.status(404).json({
          success: false,
          message: ''Todo tidak ditemukan'',
        });
      }

      res.json({
        success: true,
        message: ''Data todo ditemukan'',
        data: todo,
      });
    } catch (err) {
      next(err);
    }
  },

  // POST /api/todos
  async create(req: Request, res: Response, next: NextFunction) {
    try {
      const validation = validateCreateTodo(req.body);
      if (!validation.valid) {
        return res.status(400).json({
          success: false,
          message: ''Validasi gagal'',
          errors: validation.errors,
        });
      }

      const todo = await todoRepository.create({
        title: req.body.title.trim(),
        description: req.body.description?.trim(),
      });

      res.status(201).json({
        success: true,
        message: ''Todo berhasil dibuat'',
        data: todo,
      });
    } catch (err) {
      next(err);
    }
  },

  // PUT /api/todos/:id
  async update(req: Request, res: Response, next: NextFunction) {
    try {
      const id = parseInt(req.params.id);
      if (isNaN(id)) {
        return res.status(400).json({
          success: false,
          message: ''ID harus berupa angka'',
        });
      }

      const validation = validateUpdateTodo(req.body);
      if (!validation.valid) {
        return res.status(400).json({
          success: false,
          message: ''Validasi gagal'',
          errors: validation.errors,
        });
      }

      const todo = await todoRepository.update(id, req.body);
      if (!todo) {
        return res.status(404).json({
          success: false,
          message: ''Todo tidak ditemukan'',
        });
      }

      res.json({
        success: true,
        message: ''Todo berhasil diupdate'',
        data: todo,
      });
    } catch (err) {
      next(err);
    }
  },

  // DELETE /api/todos/:id
  async remove(req: Request, res: Response, next: NextFunction) {
    try {
      const id = parseInt(req.params.id);
      if (isNaN(id)) {
        return res.status(400).json({
          success: false,
          message: ''ID harus berupa angka'',
        });
      }

      const deleted = await todoRepository.remove(id);
      if (!deleted) {
        return res.status(404).json({
          success: false,
          message: ''Todo tidak ditemukan'',
        });
      }

      res.status(200).json({
        success: true,
        message: ''Todo berhasil dihapus'',
      });
    } catch (err) {
      next(err);
    }
  },
};
```

