## CRUD API Endpoints

```typescript
// backend/src/routes/trips.ts
import { Router, Request, Response } from ''express'';
import { PrismaClient } from ''@prisma/client'';

const router = Router();
const prisma = new PrismaClient();

// GET /api/trips — list semua trips user
router.get(''/'', async (req: Request, res: Response) => {
  const trips = await prisma.trip.findMany({
    where: { userId: req.user.id },
  });
  res.json(trips);
});

// POST /api/trips — buat trip baru
router.post(''/'', async (req: Request, res: Response) => {
  const { title, destination, startDate, endDate } = req.body;
  const trip = await prisma.trip.create({
    data: {
      title,
      destination,
      startDate: new Date(startDate),
      endDate: new Date(endDate),
      userId: req.user.id,
    },
  });
  res.status(201).json(trip);
});

// GET /api/trips/:id — detail trip
router.get(''/:id'', async (req: Request, res: Response) => {
  const trip = await prisma.trip.findFirst({
    where: { id: req.params.id, userId: req.user.id },
  });
  if (!trip) return res.status(404).json({ error: ''Trip not found'' });
  res.json(trip);
});

// PUT /api/trips/:id — update trip
router.put(''/:id'', async (req: Request, res: Response) => {
  const { title, destination, startDate, endDate } = req.body;
  const trip = await prisma.trip.update({
    where: { id: req.params.id },
    data: { title, destination, startDate, endDate },
  });
  res.json(trip);
});

// DELETE /api/trips/:id — hapus trip
router.delete(''/:id'', async (req: Request, res: Response) => {
  await prisma.trip.delete({ where: { id: req.params.id } });
  res.json({ message: ''Deleted'' });
});

export default router;
```

## Auth Middleware

```typescript
// backend/src/middleware/auth.ts
import { Request, Response, NextFunction } from ''express'';
import jwt from ''jsonwebtoken'';

interface AuthRequest extends Request {
  user?: { id: string; email: string };
}

export const authMiddleware = (
  req: AuthRequest,
  res: Response,
  next: NextFunction
) => {
  const token = req.headers.authorization?.split('' '')[1];
  if (!token) {
    return res.status(401).json({ error: ''No token provided'' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as {
      id: string;
      email: string;
    };
    req.user = decoded;
    next();
  } catch {
    res.status(401).json({ error: ''Invalid token'' });
  }
};
```

## Auth Controller

```typescript
// backend/src/controllers/auth.ts
import { Request, Response } from ''express'';
import bcrypt from ''bcrypt'';
import jwt from ''jsonwebtoken'';
import { PrismaClient } from ''@prisma/client'';

const prisma = new PrismaClient();

export const register = async (req: Request, res: Response) => {
  const { email, password } = req.body;

  const existing = await prisma.user.findUnique({ where: { email } });
  if (existing) {
    return res.status(400).json({ error: ''Email already registered'' });
  }

  const hashed = await bcrypt.hash(password, 10);
  const user = await prisma.user.create({
    data: { email, password: hashed },
  });

  const token = jwt.sign(
    { id: user.id, email: user.email },
    process.env.JWT_SECRET!,
    { expiresIn: ''7d'' }
  );

  res.status(201).json({ token, user: { id: user.id, email: user.email } });
};

export const login = async (req: Request, res: Response) => {
  const { email, password } = req.body;

  const user = await prisma.user.findUnique({ where: { email } });
  if (!user) {
    return res.status(401).json({ error: ''Invalid credentials'' });
  }

  const valid = await bcrypt.compare(password, user.password);
  if (!valid) {
    return res.status(401).json({ error: ''Invalid credentials'' });
  }

  const token = jwt.sign(
    { id: user.id, email: user.email },
    process.env.JWT_SECRET!,
    { expiresIn: ''7d'' }
  );

  res.json({ token, user: { id: user.id, email: user.email } });
};
```

## Frontend — Halaman List

```tsx
// frontend/src/pages/TripList.tsx
import { useEffect, useState } from ''react'';
import { api } from ''../api/client'';

interface Trip {
  id: string;
  title: string;
  destination: string;
  startDate: string;
}

export default function TripList() {
  const [trips, setTrips] = useState<Trip[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get(''/trips'')
      .then((res) => setTrips(res.data))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div>Loading...</div>;

  return (
    <div>
      <h1>My Trips</h1>
      {trips.map((trip) => (
        <div key={trip.id} className="card">
          <h2>{trip.title}</h2>
          <p>{trip.destination}</p>
          <p>{trip.startDate}</p>
        </div>
      ))}
    </div>
  );
}
