## Agent API Endpoint — Stream

```typescript
// backend/src/routes/ai.ts
import { Router, Request, Response } from ''express'';
import { travelAgent } from ''../agents/travelAgent'';

const router = Router();

// POST /api/ai/chat — chat dengan agent (streaming)
router.post(''/chat'', async (req: Request, res: Response) => {
  const { message } = req.body;

  res.setHeader(''Content-Type'', ''text/plain'');
  res.setHeader(''Transfer-Encoding'', ''chunked'');

  try {
    const stream = await travelAgent.stream([
      { role: ''user'', content: message },
    ]);

    for await (const chunk of stream) {
      res.write(chunk.delta?.text || '''');
    }

    res.end();
  } catch (error) {
    res.status(500).json({ error: ''AI agent error'' });
  }
});

export default router;
```

## Frontend — Chat Component

```tsx
// frontend/src/components/Chat.tsx
import { useState, useRef } from ''react'';

export default function Chat() {
  const [messages, setMessages] = useState<
    { role: ''user'' | ''ai''; content: string }[]
  >([]);
  const [input, setInput] = useState('''');
  const [loading, setLoading] = useState(false);
  const [abortController, setAbortController] =
    useState<AbortController | null>(null);

  const handleSend = async () => {
    const userMsg = { role: ''user'' as const, content: input };
    setMessages((prev) => [...prev, userMsg]);
    setInput('''');
    setLoading(true);

    const controller = new AbortController();
    setAbortController(controller);

    try {
      const res = await fetch(
        `${import.meta.env.VITE_API_URL}/ai/chat`,
        {
          method: ''POST'',
          headers: { ''Content-Type'': ''application/json'' },
          body: JSON.stringify({ message: input }),
          signal: controller.signal,
        }
      );

      const reader = res.body?.getReader();
      const decoder = new TextDecoder();

      let aiContent = '''';
      setMessages((prev) => [...prev, { role: ''ai'', content: '''' }]);

      while (reader) {
        const { done, value } = await reader.read();
        if (done) break;

        const text = decoder.decode(value);
        aiContent += text;

        setMessages((prev) => {
          const updated = [...prev];
          updated[updated.length - 1] = {
            role: ''ai'',
            content: aiContent,
          };
          return updated;
        });
      }
    } catch (err: any) {
      if (err.name !== ''AbortError'') {
        setMessages((prev) => [
          ...prev,
          { role: ''ai'', content: ''Error: gagal mendapat response'' },
        ]);
      }
    } finally {
      setLoading(false);
      setAbortController(null);
    }
  };

  const handleStop = () => {
    abortController?.abort();
  };

  return (
    <div className="chat-container">
      <div className="messages">
        {messages.map((msg, i) => (
          <div key={i} className={`message ${msg.role}`}>
            <strong>{msg.role === ''user'' ? ''You'' : ''AI''}:</strong>{'' ''}
            {msg.content}
          </div>
        ))}
      </div>
      <div className="input-area">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === ''Enter'' && handleSend()}
          disabled={loading}
          placeholder="Tanya rencana perjalanan..."
        />
        {loading ? (
          <button onClick={handleStop}>Stop</button>
        ) : (
          <button onClick={handleSend}>Send</button>
        )}
      </div>
    </div>
  );
}
```

