## Firebase Auth

### Auth Service

```dart
// services/auth_service.dart
import ''package:firebase_auth/firebase_auth.dart'';

class AuthService {
  final FirebaseAuth _auth = FirebaseAuth.instance;

  // Stream auth state — auto detect login/logout
  Stream<User?> get user => _auth.authStateChanges();

  // Register
  Future<UserCredential> register(String email, String password) async {
    return await _auth.createUserWithEmailAndPassword(
      email: email,
      password: password,
    );
  }

  // Login
  Future<UserCredential> login(String email, String password) async {
    return await _auth.signInWithEmailAndPassword(
      email: email,
      password: password,
    );
  }

  // Logout
  Future<void> logout() async {
    await _auth.signOut();
  }

  // Get current user
  User? get currentUser => _auth.currentUser;
}
```

### Login Screen

```dart
class LoginScreen extends StatefulWidget {
  const LoginScreen({super.key});

  @override
  State<LoginScreen> createState() => _LoginScreenState();
}

class _LoginScreenState extends State<LoginScreen> {
  final _emailController = TextEditingController();
  final _passwordController = TextEditingController();
  final _authService = AuthService();
  bool _isLoading = false;

  Future<void> _login() async {
    setState(() => _isLoading = true);
    try {
      await _authService.login(
        _emailController.text.trim(),
        _passwordController.text,
      );
      // Success → Navigator bakal otomatis pindah
      // karena auth state listener di main
    } on FirebaseAuthException catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text(_getErrorMessage(e.code))),
      );
    } finally {
      setState(() => _isLoading = false);
    }
  }

  String _getErrorMessage(String code) {
    switch (code) {
      case ''user-not-found'':
        return ''Email tidak terdaftar'';
      case ''wrong-password'':
        return ''Password salah'';
      case ''invalid-credential'':
        return ''Email atau password salah'';
      case ''too-many-requests'':
        return ''Terlalu banyak percobaan. Coba lagi nanti'';
      default:
        return ''Login gagal: $code'';
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text(''Login'')),
      body: Padding(
        padding: const EdgeInsets.all(24),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            TextField(
              controller: _emailController,
              decoration: const InputDecoration(
                labelText: ''Email'',
                prefixIcon: Icon(Icons.email),
                border: OutlineInputBorder(),
              ),
              keyboardType: TextInputType.emailAddress,
            ),
            const SizedBox(height: 16),
            TextField(
              controller: _passwordController,
              decoration: const InputDecoration(
                labelText: ''Password'',
                prefixIcon: Icon(Icons.lock),
                border: OutlineInputBorder(),
              ),
              obscureText: true,
            ),
            const SizedBox(height: 24),
            SizedBox(
              width: double.infinity,
              child: ElevatedButton(
                onPressed: _isLoading ? null : _login,
                child: _isLoading
                    ? const SizedBox(
                        height: 20,
                        width: 20,
                        child: CircularProgressIndicator(strokeWidth: 2),
                      )
                    : const Text(''Login''),
              ),
            ),
          ],
        ),
      ),
    );
  }

  @override
  void dispose() {
    _emailController.dispose();
    _passwordController.dispose();
    super.dispose();
  }
}
```

### Auth State Listener — Redirect Otomatis

```dart
// main.dart
class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: StreamBuilder<User?>(
        stream: FirebaseAuth.instance.authStateChanges(),
        builder: (context, snapshot) {
          if (snapshot.connectionState == ConnectionState.waiting) {
            return const Scaffold(
              body: Center(child: CircularProgressIndicator()),
            );
          }

          // Kalo login → NotesScreen, kalo enggak → LoginScreen
          if (snapshot.hasData) {
            return const NotesScreen();
          } else {
            return const LoginScreen();
          }
        },
      ),
    );
  }
}
```

### Firestore Security Rules

```text
// Firebase Console → Firestore → Rules

rules_version = ''2'';
service cloud.firestore {
  match /databases/{database}/documents {

    // Cuma user login yang bisa akses
    match /notes/{noteId} {
      allow read, write: if request.auth != null
        && request.auth.uid == resource.data.user_id;

      allow create: if request.auth != null
        && request.auth.uid == request.resource.data.user_id;
    }
  }
}
```

