## Docker Security

### Dockerfile Aman

```dockerfile
# ❌ RENTAN — jangan pake base image besar + root user
FROM node:20
COPY . /app
RUN npm install
CMD ["node", "dist/index.js"]
USER root  # ❌ Hacker dapet root akses!

# ✅ AMAN — multi-stage build + non-root user
# Stage 1: Build
FROM node:20-alpine AS builder
WORKDIR /app
COPY package*.json ./
RUN npm ci --only=production
COPY . .
RUN npm run build

# Stage 2: Production (minimal)
FROM node:20-alpine AS production
WORKDIR /app

# 1. Non-root user
RUN addgroup -g 1001 -S nodejs && \
    adduser -S nodejs -u 1001

# 2. Cuma copy yang diperlukan
COPY --from=builder /app/dist ./dist
COPY --from=builder /app/node_modules ./node_modules
COPY --from=builder /app/package.json ./

# 3. Non-root
USER nodejs

# 4. Health check
HEALTHCHECK --interval=30s --timeout=3s --start-period=5s --retries=3 \
  CMD node dist/health.js || exit 1

EXPOSE 3000
CMD ["node", "dist/index.js"]
```

### Docker Compose Aman

```yaml
# docker-compose.yml
version: ''3.8''

services:
  app:
    build: .
    ports:
      - ''3000:3000''
    environment:
      - NODE_ENV=production
    env_file:
      - .env.production
    # Jangan expose port database!
    networks:
      - internal
    # Resource limits — cegah DDoS
    deploy:
      resources:
        limits:
          cpus: ''0.5''
          memory: ''512M''
    # Root filesystem read-only
    read_only: true
    # Drop all capabilities
    cap_drop:
      - ALL
    # Jangan jalan sebagai root
    user: ''1001:1001''

  postgres:
    image: postgres:16-alpine
    environment:
      - POSTGRES_PASSWORD_FILE=/run/secrets/db_password
    # Jangan expose port ke host!
    # ports: - ''5432:5432'' ❌
    expose:
      - ''5432'' # cuma container lain di network yang bisa akses
    secrets:
      - db_password
    networks:
      - internal
    volumes:
      - pgdata:/var/lib/postgresql/data

secrets:
  db_password:
    file: ./secrets/db_password.txt

volumes:
  pgdata:

networks:
  internal:
    driver: bridge
```

### Scan Docker Image for Vulns

```bash
# Trivy — open-source container scanner
# Install
sudo apt install trivy

# Scan image
trivy image myapp:latest

# Scan dengan threshold
trivy image --severity CRITICAL,HIGH myapp:latest

# Output JSON
trivy image --format json --output report.json myapp:latest

# Di CI
# - Fails pipeline kalo ada CRITICAL vuln
```

