   async function reg(a: any, b: any) {
     if (!a || !b) {
       return 0;
     }
     const x = await db.query(`SELECT * FROM users WHERE email = ''${b}''`);
     if (x.length > 0) {
       return "exists";
     }
     const y = await db.query(`INSERT INTO users(name,email) VALUES(''${a}'',''${b}'')`);
     sendEmail(b, "Welcome");
     return y;
   }
