## 2. CI/CD dengan Lighthouse CI

### Setup Lighthouse CI (LHCI)

```bash
npm install --save-dev @lhci/cli
```

```typescript
// lighthouserc.js
module.exports = {
  ci: {
    collect: {
      url: [
        ''http://localhost:3000/'',
        ''http://localhost:3000/products'',
        ''http://localhost:3000/cart'',
      ],
      startServerCommand: ''npm run start'',
      numberOfRuns: 3,              // Rata-rata dari 3 run
      settings: {
        preset: ''desktop'',
        onlyCategories: [''performance'', ''accessibility'', ''seo'', ''best-practices''],
      },
    },
    upload: {
      target: ''filesystem'',        // Simpan report lokal
      outputDir: ''./lhci-reports'',
      reportFilenamePattern: ''lighthouse-%%URLNAME%%-%%DATETIME%%.html'',
    },
    assert: {
      preset: ''lighthouse:no-pwa'',  // Assertions default
      assertions: {
        ''categories:performance'': [''warn'', { minScore: 0.9 }],
        ''categories:accessibility'': [''error'', { minScore: 0.9 }],
        ''categories:seo'': [''error'', { minScore: 0.9 }],
        ''categories:best-practices'': [''error'', { minScore: 0.9 }],
        ''lighthouse-disk-cache'': ''off'',
        ''unused-javascript'': [''warn'', { maxLength: 0 }],
      },
    },
  },
};
```

### GitHub Actions — Lighthouse CI

```yaml
# .github/workflows/lighthouse.yml
name: Lighthouse CI
on:
  push:
    branches: [main]
  pull_request:
    branches: [main]

jobs:
  lighthouse:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: 20
          cache: ''npm''

      - name: Install dependencies
        run: npm ci

      - name: Build
        run: npm run build

      - name: Run Lighthouse CI
        run: |
          npm install -g @lhci/cli
          lhci autorun
        env:
          LHCI_GITHUB_APP_TOKEN: ${{ secrets.LHCI_GITHUB_APP_TOKEN }}
```

### GitLab CI — Lighthouse

```yaml
# .gitlab-ci.yml
image: node:20

stages:
  - build
  - test
  - lighthouse

lighthouse:
  stage: lighthouse
  script:
    - npm ci
    - npm run build
    - npm install -g @lhci/cli
    - lhci autorun --config=./lighthouserc.js
  artifacts:
    paths:
      - lhci-reports/
    expire_in: 30 days
  only:
    - main
```

