    .search-container { max-width: 600px; margin: 40px auto; font-family: sans-serif; }
    #search-input { width: 100%; padding: 12px; font-size: 16px; border: 2px solid #ddd; border-radius: 8px; }
    #search-results { margin-top: 12px; }
