## 💻 Kode Praktik

### RTLWrapper Component

```typescript
// src/components/RTLWrapper.tsx
import { useEffect } from ''react'';
import { useTranslation } from ''react-i18next'';

export function RTLWrapper({ children }: { children: React.ReactNode }) {
  const { i18n } = useTranslation();

  useEffect(() => {
    const dir = i18n.dir();
    const lang = i18n.language;

    document.documentElement.dir = dir;
    document.documentElement.lang = lang;

    // update CSS custom property untuk bg position dll
    document.documentElement.style.setProperty(
      ''--dir-start'',
      dir === ''rtl'' ? ''right'' : ''left''
    );
    document.documentElement.style.setProperty(
      ''--dir-end'',
      dir === ''rtl'' ? ''left'' : ''right''
    );
  }, [i18n.language]);

  return <>{children}</>;
}
```

### Express Server Lengkap

```bash
npm install express cors
```

```typescript
// server.ts
import express from ''express'';
import cors from ''cors'';
import { i18nMiddleware } from ''./middleware/i18n'';

const app = express();
app.use(cors());
app.use(express.json());
app.use(i18nMiddleware);

app.get(''/api/greeting'', (req, res) => {
  const locale = req.locale;
  const greetings: Record<string, string> = {
    en: ''Hello!'',
    id: ''Halo!'',
    ar: ''مرحبا!'',
  };
  res.json({
    message: greetings[locale] ?? greetings[''en''],
    locale,
  });
});

app.listen(3001, () => console.log(''Server on :3001''));
```

