            <LanguageSwitcher />
            <HreflangTags
              currentPath="/"
              siteUrl="https://example.com"
            />
            <Routes>
              <Route path="/" element={<Home />} />
            </Routes>
          </RTLWrapper>
        </I18nSuspense>
      </BrowserRouter>
