## 4.2 Env Validation dengan dotenv + Zod

### Instalasi

```bash
npm install dotenv zod
```

### File `.env`

```bash
# .env — jangan di-commit!
# copy ke .env.example untuk dokumentasi
PORT=3000
NODE_ENV=development
DATABASE_URL=postgresql://user:password@localhost:5432/mydb
REDIS_URL=redis://localhost:6379
JWT_SECRET=my-super-secret-key
LOG_LEVEL=debug
CORS_ORIGIN=http://localhost:5173
```

### Zod Env Schema

```typescript
// env.ts
import { z } from ''zod'';
import dotenv from ''dotenv'';

// Load .env file
dotenv.config();

// Schema validasi env
const envSchema = z.object({
  // App
  NODE_ENV: z.enum([''development'', ''staging'', ''production'']).default(''development''),
  PORT: z.coerce.number().int().positive().max(65535).default(3000),

  // Database
  DATABASE_URL: z.string().url(),
  DB_POOL_MIN: z.coerce.number().int().min(0).default(2),
  DB_POOL_MAX: z.coerce.number().int().min(1).max(100).default(10),

  // Redis
  REDIS_URL: z.string().url().optional(),

  // Auth
  JWT_SECRET: z.string().min(32, ''JWT_SECRET minimal 32 karakter''),
  JWT_EXPIRES_IN: z.string().default(''7d''),

  // CORS
  CORS_ORIGIN: z.string().default(''http://localhost:5173''),

  // Logging
  LOG_LEVEL: z.enum([''error'', ''warn'', ''info'', ''debug'']).default(''info''),

  // Feature flags
  ENABLE_CACHE: z.coerce.boolean().default(true),
  ENABLE_RATE_LIMIT: z.coerce.boolean().default(true),
});

// Parse dan validasi
const parsedEnv = envSchema.safeParse(process.env);

if (!parsedEnv.success) {
  console.error(''❌ Environment variables tidak valid:'');
  for (const issue of parsedEnv.error.issues) {
    console.error(`  - ${issue.path.join(''.'')}: ${issue.message}`);
  }
  process.exit(1);
}

// Export validated config
export const env = parsedEnv.data;

// Type dari schema
export type Env = z.infer<typeof envSchema>;
```

### Penggunaan

```typescript
// app.ts
import { env } from ''./env'';

const app = express();

app.listen(env.PORT, () => {
  console.log(`Server berjalan di port ${env.PORT} (${env.NODE_ENV})`);
});

// Koneksi database
const db = new Pool({
  connectionString: env.DATABASE_URL,
  min: env.DB_POOL_MIN,
  max: env.DB_POOL_MAX,
});
```

### `.env.example`

```bash
# .env.example — dokumentasi, di-commit ke repo
# Copy file ini ke .env dan isi nilainya

# =========== APP ===========
# Environment: development | staging | production
NODE_ENV=development
# Port aplikasi
PORT=3000

# =========== DATABASE ===========
# Contoh: postgresql://user:password@host:5432/dbname
DATABASE_URL=postgresql://user:pass@localhost:5432/mydb
# Pool koneksi (opsional, default: min=2, max=10)
DB_POOL_MIN=2
DB_POOL_MAX=10

# =========== REDIS ===========
# Untuk caching dan session (opsional)
# REDIS_URL=redis://localhost:6379

# =========== AUTH ===========
# JWT secret key — minimal 32 karakter
JWT_SECRET=your-secret-key-change-in-production
# JWT expiry (contoh: 7d, 1h, 30m)
JWT_EXPIRES_IN=7d

# =========== CORS ===========
# Origin yang diizinkan
CORS_ORIGIN=http://localhost:5173

# =========== LOGGING ===========
# Level: error | warn | info | debug
LOG_LEVEL=info

# =========== FEATURE FLAGS ===========
ENABLE_CACHE=true
ENABLE_RATE_LIMIT=true
```

