## 2. Traefik API Gateway

### 2.1 Kenapa Traefik?

| Fitur | Traefik | Nginx | Express Gateway |
|-------|---------|-------|-----------------|
| Konfigurasi | Dynamic (auto-detect containers) | Static file | Static file |
| Service discovery | Docker, Kubernetes, Consul | Manual upstream | Manual |
| Hot reload | Yes (no restart) | No (reload config) | No (restart) |
| Dashboard GUI | ✅ | ❌ | ❌ |
| Let''s Encrypt | Auto | Manual | Manual |
| Middleware | Built-in | Lua/3rd party | Plugin |

### 2.2 Traefik Configuration

```yaml
# gateway/traefik.yml — static configuration
api:
  dashboard: true
  debug: true

entryPoints:
  web:
    address: ":80"
  websecure:
    address: ":443"

providers:
  docker:
    endpoint: "unix:///var/run/docker.sock"
    exposedByDefault: false    # Hanya service dengan label traefik.enable=true
    swarmMode: false
    network: ms-backend

  file:
    filename: /etc/traefik/dynamic.yml
    watch: true

certificatesResolvers:
  letsencrypt:
    acme:
      email: admin@example.com
      storage: /etc/traefik/acme.json
      httpChallenge:
        entryPoint: web

# Global middleware
log:
  level: INFO
  filePath: /var/log/traefik.log

accessLog:
  filePath: /var/log/access.log
  format: json
```

```yaml
# gateway/dynamic.yml — dynamic routing rules
http:
  routers:
    # =====================
    # User Service Routes
    # =====================
    user-service-api:
      rule: "PathPrefix(`/api/users`) || PathPrefix(`/api/auth`)"
      service: user-service
      entryPoints:
        - web
      middlewares:
        - auth-middleware
        - rate-limit
        - cors-headers
      priority: 10

    user-service-health:
      rule: "PathPrefix(`/health/user`)"
      service: user-service
      entryPoints:
        - web
      middlewares: []
      # No auth untuk health check

    # =====================
    # Product Service Routes
    # =====================
    product-service-api:
      rule: "PathPrefix(`/api/products`)"
      service: product-service
      entryPoints:
        - web
      middlewares:
        - auth-middleware
        - rate-limit
        - cors-headers
      priority: 10

    # =====================
    # Order Service Routes
    # =====================
    order-service-api:
      rule: "PathPrefix(`/api/orders`)"
      service: order-service
      entryPoints:
        - web
      middlewares:
        - auth-middleware
        - rate-limit
        - cors-headers
      priority: 10

    # =====================
    # Dashboard (Traefik)
    # =====================
    dashboard:
      rule: "PathPrefix(`/api/dashboard`) || PathPrefix(`/dashboard`)"
      service: api@internal
      entryPoints:
        - web
      middlewares:
        - dashboard-auth
      priority: 1

  # =====================
  # Middleware Definitions
  # =====================
  middlewares:
    # Auth — validasi JWT
    auth-middleware:
      forwardAuth:
        address: "http://user-service:3001/internal/verify-token"
        trustForwardHeader: true
        authResponseHeaders:
          - X-User-Id
          - X-User-Role
          - X-User-Email

    # Rate Limiting
    rate-limit:
      rateLimit:
        average: 100       # 100 request per...
        period: 1m         # ...menit
        burst: 10          # burst allowance
        sourceCriterion:
          ipStrategy:
            depth: 1

    # CORS
    cors-headers:
      headers:
        accessControlAllowOriginList:
          - "http://localhost:3000"
          - "https://app.example.com"
        accessControlAllowMethods:
          - GET
          - POST
          - PUT
          - DELETE
          - PATCH
        accessControlAllowHeaders:
          - Authorization
          - Content-Type
          - X-Correlation-Id
        accessControlExposeHeaders:
          - X-Correlation-Id
          - X-Request-Id
        accessControlAllowCredentials: true

    # Dashboard basic auth
    dashboard-auth:
      basicAuth:
        users:
          - "admin:$2y$10$..."  # bcrypt hash

  # =====================
  # Services (Backends)
  # =====================
  services:
    user-service:
      loadBalancer:
        servers:
          - url: "http://user-service:3001"
        healthCheck:
          path: /health
          interval: 30s
          timeout: 5s

    product-service:
      loadBalancer:
        servers:
          - url: "http://product-service:3002"
        healthCheck:
          path: /health
          interval: 30s
          timeout: 5s

    order-service:
      loadBalancer:
        servers:
          - url: "http://order-service:3003"
        healthCheck:
          path: /health
          interval: 30s
          timeout: 5s
```

### 2.3 Docker Compose Labels (Auto-Discovery)

Alternatif — tanpa dynamic.yml, bisa pakai Docker labels langsung:

```yaml
# docker-compose.yml — Traefik auto-discover via labels
services:
  user-service:
    image: user-service:latest
    labels:
      - "traefik.enable=true"
      
      # Router
      - "traefik.http.routers.user-service.rule=PathPrefix(`/api/users`) || PathPrefix(`/api/auth`)"
      - "traefik.http.routers.user-service.entrypoints=web"
      - "traefik.http.routers.user-service.middlewares=auth-middleware,rate-limit"
      
      # Service
      - "traefik.http.services.user-service.loadbalancer.server.port=3001"
      
      # Middleware (global, shared via file provider)
      - "traefik.http.middlewares.rate-limit.ratelimit.average=100"
      - "traefik.http.middlewares.rate-limit.ratelimit.period=1m"

  gateway:
    image: traefik:v3.0
    volumes:
      - /var/run/docker.sock:/var/run/docker.sock
    labels:
      - "traefik.enable=true"
      - "traefik.http.routers.dashboard.rule=PathPrefix(`/dashboard`)"
      - "traefik.http.routers.dashboard.service=api@internal"
```

