### `js/testimonial.js`
```javascript
document.addEventListener(''DOMContentLoaded'', function() {
    const slides = document.querySelectorAll(''.testimonial-slide'');
    let currentSlide = 0;
    
    function showSlide(index) {
        slides.forEach(slide => slide.classList.remove(''active''));
        slides[index].classList.add(''active'');
    }
    
    function nextSlide() {
        currentSlide = (currentSlide + 1) % slides.length;
        showSlide(currentSlide);
    }
    
    if (slides.length > 0) {
        showSlide(0);
        setInterval(nextSlide, 5000);
    }
});
```

### `js/form.js`
```javascript
document.addEventListener(''DOMContentLoaded'', function() {
    const form = document.getElementById(''contactForm'');
    if (!form) return;
    
    const messagesContainer = document.getElementById(''messagesList'');
    
    // Load existing messages
    loadMessages();
    
    form.addEventListener(''submit'', function(e) {
        e.preventDefault();
        
        // Reset errors
        document.querySelectorAll(''.error'').forEach(el => el.remove());
        
        // Get values
        const name = document.getElementById(''name'').value.trim();
        const email = document.getElementById(''email'').value.trim();
        const phone = document.getElementById(''phone'').value.trim();
        const message = document.getElementById(''message'').value.trim();
        
        let isValid = true;
        
        // Validation
        if (!name) {
            showError(''name'', ''Nama harus diisi'');
            isValid = false;
        }
        
        if (!email) {
            showError(''email'', ''Email harus diisi'');
            isValid = false;
        } else if (!isValidEmail(email)) {
            showError(''email'', ''Format email tidak valid'');
            isValid = false;
        }
        
        if (!message) {
            showError(''message'', ''Pesan harus diisi'');
            isValid = false;
        } else if (message.length < 10) {
            showError(''message'', ''Pesan minimal 10 karakter'');
            isValid = false;
        }
        
        if (!isValid) return;
        
        // Save message
        const messages = JSON.parse(localStorage.getItem(''contacts'') || ''[]'');
        messages.push({
            id: Date.now(),
            name,
            email,
            phone,
            message,
            date: new Date().toISOString()
        });
        localStorage.setItem(''contacts'', JSON.stringify(messages));
        
        // Clear form
        form.reset();
        
        // Reload messages
        loadMessages();
        
        alert(''Pesan berhasil dikirim!'');
    });
    
    function showError(fieldId, msg) {
        const field = document.getElementById(fieldId);
        const error = document.createElement(''div'');
        error.className = ''error'';
        error.style.color = ''red'';
        error.style.fontSize = ''0.85rem'';
        error.textContent = msg;
        field.parentNode.insertBefore(error, field.nextSibling);
    }
    
    function isValidEmail(email) {
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
    }
    
    function loadMessages() {
        if (!messagesContainer) return;
        const messages = JSON.parse(localStorage.getItem(''contacts'') || ''[]'');
        
        if (messages.length === 0) {
            messagesContainer.innerHTML = ''<p>Belum ada pesan.</p>'';
            return;
        }
        
        messagesContainer.innerHTML = messages.map(msg => `
            <div class="message-item">
                <strong>${escapeHtml(msg.name)}</strong> (${escapeHtml(msg.email)})
                <p>${escapeHtml(msg.message)}</p>
                <small>${new Date(msg.date).toLocaleString()}</small>
            </div>
        `).join('''');
    }
    
    function escapeHtml(str) {
        const div = document.createElement(''div'');
        div.textContent = str;
        return div.innerHTML;
    }
});
```

### `js/admin.js`
```javascript
document.addEventListener(''DOMContentLoaded'', function() {
    // Check login status
    const isLoggedIn = sessionStorage.getItem(''adminLoggedIn'');
    const loginForm = document.getElementById(''loginForm'');
    const adminContent = document.getElementById(''adminContent'');
    
    if (isLoggedIn === ''true'') {
        showAdmin();
    }
    
    if (loginForm) {
        loginForm.addEventListener(''submit'', function(e) {
            e.preventDefault();
            const username = document.getElementById(''username'').value;
            const password = document.getElementById(''password'').value;
            
            if (username === ''admin'' && password === ''admin123'') {
                sessionStorage.setItem(''adminLoggedIn'', ''true'');
                showAdmin();
            } else {
                alert(''Username atau password salah!'');
            }
        });
    }
    
    function showAdmin() {
        if (loginForm) loginForm.style.display = ''none'';
        if (adminContent) {
            adminContent.style.display = ''block'';
            loadAdminMessages();
        }
    }
    
    function loadAdminMessages() {
        const list = document.getElementById(''adminMessagesList'');
        const messages = JSON.parse(localStorage.getItem(''contacts'') || ''[]'');
        
        if (messages.length === 0) {
            list.innerHTML = ''<p>Tidak ada pesan.</p>'';
            return;
        }
        
        list.innerHTML = messages.map(msg => `
            <div class="admin-message">
                <p><strong>${escapeHtml(msg.name)}</strong> — ${escapeHtml(msg.email)}</p>
                <p>${escapeHtml(msg.message)}</p>
                <small>${new Date(msg.date).toLocaleString()}</small>
                <button onclick="deleteMessage(${msg.id})" class="btn-delete">Hapus</button>
            </div>
        `).join('''');
    }
    
    window.deleteMessage = function(id) {
        let messages = JSON.parse(localStorage.getItem(''contacts'') || ''[]'');
        messages = messages.filter(msg => msg.id !== id);
        localStorage.setItem(''contacts'', JSON.stringify(messages));
        loadAdminMessages();
    };
    
    window.logout = function() {
        sessionStorage.removeItem(''adminLoggedIn'');
        location.reload();
    };
    
    function escapeHtml(str) {
        const div = document.createElement(''div'');
        div.textContent = str;
        return div.innerHTML;
    }
});
```

