### `books.php`
```php
<?php
session_start();
if (!isset($_SESSION[''admin_logged_in'']) || $_SESSION[''admin_logged_in''] !== true) {
    header(''Location: login.php'');
    exit;
}

require_once ''config/database.php'';

$page = isset($_GET[''page'']) ? (int)$_GET[''page''] : 1;
$limit = 10;
$offset = ($page - 1) * $limit;
$search = $_GET[''search''] ?? '''';

// Handle CRUD
if ($_SERVER[''REQUEST_METHOD''] === ''POST'') {
    if (isset($_POST[''action''])) {
        // Add book
        if ($_POST[''action''] === ''add'') {
            $stmt = $pdo->prepare("INSERT INTO books (title, author, isbn, category, year, stock) VALUES (?, ?, ?, ?, ?, ?)");
            $stmt->execute([
                $_POST[''title''],
                $_POST[''author''],
                $_POST[''isbn''],
                $_POST[''category''],
                $_POST[''year''],
                $_POST[''stock''] ?? 1
            ]);
        }
        // Edit book
        elseif ($_POST[''action''] === ''edit'') {
            $stmt = $pdo->prepare("UPDATE books SET title=?, author=?, isbn=?, category=?, year=?, stock=? WHERE id=?");
            $stmt->execute([
                $_POST[''title''],
                $_POST[''author''],
                $_POST[''isbn''],
                $_POST[''category''],
                $_POST[''year''],
                $_POST[''stock''] ?? 1,
                $_POST[''id'']
            ]);
        }
        // Delete book
        elseif ($_POST[''action''] === ''delete'') {
            $stmt = $pdo->prepare("DELETE FROM books WHERE id = ?");
            $stmt->execute([$_POST[''id'']]);
        }
        header(''Location: books.php'');
        exit;
    }
}

// Build query
$where = '''';
$params = [];
if ($search) {
    $where = "WHERE title LIKE ? OR author LIKE ?";
    $params = ["%$search%", "%$search%"];
}

$total = $pdo->prepare("SELECT COUNT(*) FROM books $where");
$total->execute($params);
$totalBooks = $total->fetchColumn();
$totalPages = ceil($totalBooks / $limit);

$stmt = $pdo->prepare("SELECT * FROM books $where ORDER BY created_at DESC LIMIT $limit OFFSET $offset");
$stmt->execute($params);
$books = $stmt->fetchAll();
?>
